def create_publisher_from_env() -> SQSPIIPublisher:
    """Factory function to create a publisher from environment variables.

    Expected environment variables:
        SQS_QUEUE_URL: The SQS queue URL
        KMS_KEY_ID: (Optional) AWS KMS key ID for envelope encryption
        ENCRYPTION_KEY_B64: (Optional) Base64-encoded 32-byte key for local encryption
        AWS_REGION: (Optional) AWS region, defaults to us-east-1
    """
    queue_url = os.environ.get("SQS_QUEUE_URL")
    if not queue_url:
        raise EnvironmentError("SQS_QUEUE_URL environment variable is required")

    kms_key_id = os.environ.get("KMS_KEY_ID")
    encryption_key = None

    if not kms_key_id:
        key_b64 = os.environ.get("ENCRYPTION_KEY_B64")
        if key_b64:
            encryption_key = base64.b64decode(key_b64)
        else:
            raise EnvironmentError(
                "Either KMS_KEY_ID or ENCRYPTION_KEY_B64 environment variable is required"
            )

    region = os.environ.get("AWS_REGION", "us-east-1")

    return SQSPIIPublisher(
        queue_url=queue_url,
        encryption_key=encryption_key,
        kms_key_id=kms_key_id,
        region_name=region,
        enable_encryption=True,
    )


